const baseUrl = "https://www.livinginsider.com/searchword";
const source = "LivingInsider";
const selector = 'a[href*="/livingdetail/"][title]';
const subSelector = 'div.wordwrap-box,div.price_topic,div.detail-list-property.mb-0';
const domain = "https://www.livinginsider.com";

const page_start = 1;
const page_stop = 5;

// --------------------
// Filters
// --------------------
const regions = [
  { name: "กรุงเทพ"},
  { name: "นนทบุรี"}
];

const propertyTypes = [
  { name: "Townhome"},
  { name: "Home"},
  { name: "Land"},
  { name: "Condo"}
];

const items = [];

for (const region of regions) {
  for (const property of propertyTypes) {
    for (let page = page_start; page <= page_stop; page++) {


      const suffixUrl =
      `/${property.name}` +
      `/Buysell` +
      `/${page}` +
      `/${region.name}.html`

      items.push({
        url: `${baseUrl}${suffixUrl}`,
        selector,
        source,
        subSelector,
        domain
      });

    }

  }
}

return items;

// 1. ดึงค่า domain จากโหนดต้นทาง
const domain = $('Generate Main Page URL List').first().json.domain;

// 2. รวบรวมข้อมูลจากทุก Item
const allExtracted = items.flatMap(item => item.json.solution?.extracted_data ?? []);

// 3. ดึง URL ออกจาก HTML และทำ Unique
const urls = [...new Set(
  allExtracted
    .map(x => {
      const html = x.html || "";
      const m = html.match(/<a\s+[^>]*href="([^"]+)"/i);
      return m ? m[1] : null;
    })
    .filter(Boolean)
)];

// 4. ตรวจสอบและเติม Domain
return urls.map(rawUrl => {
  let finalUrl = rawUrl;

  try {
    // ใช้ URL constructor: ถ้า rawUrl เป็น path เช่น /ads มันจะเอาไปต่อกับ domain
    // แต่ถ้า rawUrl เป็น full URL อยู่แล้ว มันจะใช้ค่าเดิมของมันเอง
    const u = new URL(rawUrl, domain); 

    // จัดการเรื่อง Decode และประกอบ URL กลับเข้าไป
    finalUrl = u.origin + decodeURIComponent(u.pathname) + u.search;
  } catch (e) {
    // กรณีที่ rawUrl หรือ domain มีรูปแบบผิดพลาดจนสร้าง URL object ไม่ได้
    finalUrl = decodeURIComponent(rawUrl);

    // ถ้ายังไม่มี http นำหน้า ให้เอา domain แปะเข้าไปแบบ manual
    if (!finalUrl.startsWith('http')) {
      const base = domain.endsWith('/') ? domain.slice(0, -1) : domain;
      const path = finalUrl.startsWith('/') ? finalUrl : '/' + finalUrl;
      finalUrl = base + path;
    }
  }

  return {
    json: {
      url: finalUrl,
      source: $('Generate Main Page URL List').first().json.source,
      selector: $('Generate Main Page URL List').first().json.subSelector
    }
  };
});

// 1. รวบรวมข้อมูลและจัดการ URL ก่อนทำ Filtering
const allData = items
  .map(item => {
    let rawUrl = item.json.solution?.url || "";
    let decodedUrl = rawUrl;

    if (rawUrl) {
      try {
        // ตัด Fragment Identifier (#) ออกก่อน
        const urlWithoutFragment = rawUrl.split('#')[0];

        // ลอง parse ด้วย URL object เพื่อจัดการเรื่องการประกอบ origin/path/search
        const u = new URL(urlWithoutFragment);
        decodedUrl = u.origin + decodeURIComponent(u.pathname) + u.search;
      } catch (e) {
        // กรณีไม่ใช่ Full URL หรือ URL รูปแบบผิด ให้ decode ตรงๆ และตัด # เอง
        decodedUrl = decodeURIComponent(rawUrl.split('#')[0]);
      }
    }

    return {
      url: decodedUrl,
      extracted_data: item.json.solution?.extracted_data
    };
  })
  .filter(item => {
    const data = item.extracted_data;
    // เงื่อนไขการกรอง: ต้องไม่ null, ไม่ว่าง, และไม่ใช่ Array ว่าง
    if (data === undefined || data === null) return false;
    if (typeof data === 'string' && data.trim() === "") return false;
    if (Array.isArray(data) && data.length === 0) return false;
    // กรองกรณี URL ว่างด้วย (ถ้าจำเป็น)
    if (!item.url || item.url.trim() === "") return false;

    return true;
  });

// 2. แบ่งกลุ่ม (Chunking) ละ 20 ตัว
const chunkSize = 20;
const results = [];

for (let i = 0; i < allData.length; i += chunkSize) {
  const chunk = allData.slice(i, i + chunkSize);
  results.push({
    json: {
      data_set: chunk,
      count: chunk.length,
      source: $('Generate Main Page URL List').first().json.source
    }
  });
}

return results;
